const toArr = (s) => [...new Set(s.split(/\s+/).filter(w=>w.length>1))];
export const EASY_ARR    = toArr(WORDS_EASY);
export const MED_ARR     = toArr(WORDS_MED);
export const HARD_ARR    = toArr(WORDS_HARD);
export const VHARD_ARR   = toArr(WORDS_VERY_HARD);
export const IMPOSSIBLE_ARR = toArr(WORDS_IMPOSSIBLE);
export const ALL_WORDS   = [...new Set([...EASY_ARR,...MED_ARR,...HARD_ARR,...VHARD_ARR])];

export const WORD_CATEGORIES = {
  animals:     toArr(WORDS_ANIMALS),
  countries:   toArr(WORDS_COUNTRIES),
  fruits:      toArr(WORDS_FRUITS),
  food:        toArr(WORDS_FOOD),
  science:     toArr(WORDS_SCIENCE),
  sports:      toArr(WORDS_SPORTS),
  tech:        toArr(WORDS_TECH),
  programming: toArr(WORDS_PROGRAMMING),
  mythology:   toArr(WORDS_MYTHOLOGY),
  geography:   toArr(WORDS_GEOGRAPHY),
  colors:      toArr(WORDS_COLORS),
};

export const CATEGORY_NAMES = {
  animals:"🐾 Animals", countries:"🌍 Countries", fruits:"🍎 Fruits",
  food:"🍕 Food", science:"🔬 Science", sports:"⚽ Sports",
  tech:"💻 Tech", programming:"👨‍💻 Programming", mythology:"⚡ Mythology",
  geography:"🗺️ Geography", colors:"🎨 Colors",
};

export function pickWords(n, pool = ALL_WORDS) {
  if(!Array.isArray(pool)) pool = toArr(pool);
  const out=[];
  for(let i=0;i<n;i++) out.push(pool[Math.floor(Math.random()*pool.length)]);
  return out;
}
export function pickByDiff(n, diff="med") {
  const p = diff==="easy"?EASY_ARR:diff==="hard"?HARD_ARR:diff==="vhard"?VHARD_ARR:diff==="impossible"?IMPOSSIBLE_ARR:MED_ARR;
  return pickWords(n,p);
}

